// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define PI 3.14159265358979323846
#define EPS 1e-9

// Structure to represent a point
typedef struct {
    int x, y, b;
} Point;

// Function to calculate the orientation of three points
int orientation(Point p, Point q, Point r) {
    int val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
    if (val == 0) return 0; // Collinear
    return (val > 0) ? 1 : 2; // Clockwise or counterclockwise
}

// Function to calculate the convex hull using Graham's scan
void convexHull(Point points[], int n, Point hull[]) {
    int l = 0;
    for (int i = 1; i < n; i++) {
        if (points[i].x < points[l].x) l = i;
    }
    int p = l, q;
    do {
        hull[p] = points[l];
        q = (p + 1) % n;
        for (int i = 0; i < n; i++) {
            if (orientation(points[l], points[i], points[q]) == 2) q = i;
        }
        l = q;
        p = (p + 1) % n;
    } while (p != l);
}

// Function to calculate the minimum beauty of convex polygons
void minBeauty(Point points[], int n, int k) {
    Point hull[n];
    convexHull(points, n, hull);
    int dp[n][n];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            dp[i][j] = 0;
        }
    }
    for (int i = 0; i < n; i++) {
        dp[i][i] = hull[i].b;
    }
    for (int len = 2; len <= k; len++) {
        for (int i = 0; i < n - len + 1; i++) {
            int j = i + len - 1;
            dp[i][j] = INT_MAX;
            for (int k = i; k < j; k++) {
                dp[i][j] = min(dp[i][j], dp[i][k] + dp[k + 1][j]);
            }
            dp[i][j] += hull[i].b + hull[j].b;
        }
    }
    printf("%d ", dp[0][n - 1]);
}

int main() {
    int n;
    scanf("%d", &n);
    Point points[n];
    for (int i = 0; i < n; i++) {
        scanf("%d %d %d", &points[i].x, &points[i].y, &points[i].b);
    }
    for (int k = 3; k <= n; k++) {
        minBeauty(points, n, k);
    }
    return 0;
}

