        return (val > 0) ? 1 : 2; // Clockwise or counterclockwise
    }

    // Function to calculate the convex hull using Graham's scan
    static ArrayList<Point> convexHull(ArrayList<Point> points) {
        int n = points.size();
        int l = 0;
        for (int i = 1; i < n; i++) {
            if (points.get(i).x < points.get(l).x) l = i;
        }
        int p = l, q;
        ArrayList<Point> hull = new ArrayList<>();
        do {
            hull.add(points.get(l));
            q = (p + 1) % n;
            for (int i = 0; i < n; i++) {
                if (orientation(points.get(l), points.get(i), points.get(q)) == 2) q = i;
            }
            l = q;
            p = (p + 1) % n;
        } while (p != l);
        return hull;
    }

    // Function to calculate the minimum beauty of convex polygons
    static void minBeauty(ArrayList<Point> points, int k) {
        ArrayList<Point> hull = convexHull(points);
        int n = hull.size();
        int[][] dp = new int[n][n];
        for (int i = 0; i < n; i++) {
            dp[i][i] = hull.get(i).b;
        }
        for (int len = 2; len <= k; len++) {
            for (int i = 0; i < n - len + 1; i++) {
                int j = i + len - 1;
                dp[i][j] = Integer.MAX_VALUE;
                for (int l = i; l < j; l++) {
                    dp[i][j] = Math.min(dp[i][j], dp[i][l] + dp[l + 1][j]);
                }
